class Solution {
    public int countDigitOne(int n) {
        int count = 0;
        for (int i = 1; i <= n; i *= 10) {
            int div = n / (i * 10);
            count += div * i;
            count += Math.min(Math.max(n % (i * 10) - i + 1, 0), i);
        }
        return count;
    }
}
